@import (reference) '../../style/themes/index';

// ================================================================
// =                    Form Validate Animation                   =
// ================================================================

@form-prefix-cls: ~'@{ant-prefix}-form';

@animation-duration: @animation-duration-slow;
@animate-distance: -5px;

.animation(@type) {
  &-@{type} {
    animation: ~"@{type}" @animation-duration @ease-in-out;
  }
}

.keyframes(@name; @from-opacity; @to-opacity; @from-transform; @to-transform) {
  @keyframes @name {
    from {
      transform: @from-transform;
      opacity: @from-opacity;
    }

    to {
      transform: @to-transform;
      opacity: @to-opacity;
    }
  }
}

.@{form-prefix-cls}-validate_animation {
  .animation(enter);
  .animation(leave);

  .keyframes(enter; 0; 1; translateY(@animate-distance); translateY(0));
  .keyframes(leave; 1; 0; translateY(0); translateY(@animate-distance));
}

@import (reference) "../style/themes/default.less";

.am-guide .am-button-ghost {
  --am-button-ghost-border-color: @color-text-base;
  --am-button-ghost-color: @color-text-base;
}
.am-guide {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  &-content {
    position: relative;
    z-index: 2;
    width: 100vw;
    height: 100vh;
    overflow: hidden;
    padding-bottom: 208 * @pixelSize;
    box-sizing: border-box;
    &-pager {
      padding-bottom: 260 * @pixelSize;
    }
  }
  &-img {
    position: absolute;
    z-index: 2;
  }
  &-btn {
    position: absolute;
    bottom: 120 * @pixelSize;
    left: 0;
    right: 0;
    display: flex;
    justify-content: center;
    z-index: 5;
    &-item {
      margin-right: @h-spacing-large;
      &:last-child {
        margin-right: 0;
      }
    }
  }
  &-pager {
    position: absolute;
    bottom: 196 * @pixelSize;
    left: 0;
    right: 0;
    z-index: 5;
  }
}

@class-prefix-badge: ~'adm-badge';

.@{class-prefix-badge}-wrapper {
  display: inline-block;
  position: relative;
}

.@{class-prefix-badge} {
  display: inline-flex;
  vertical-align: middle;
  box-sizing: content-box;
  border-radius: 100px;
  background-color: var(--color);
  --right: 0;
  --top: 0;
  --color: var(--adm-badge-color, var(--adm-color-highlight));

  &-content {
    color: var(--adm-color-text-light-solid);
    box-sizing: border-box;
    min-width: 8px;
    padding: 1px 4px;
    font-size: var(--adm-font-size-1);
    line-height: 12px;
    white-space: nowrap;
    font-weight: normal;
    text-align: center;
  }

  &-fixed {
    position: absolute;
    right: var(--right);
    top: var(--top);
    transform: translate(50%, -50%);
  }

  &-dot {
    min-width: 10px;
    width: 10px;
    height: 10px;
    border-radius: 5px;
  }

  &-bordered {
    border: solid 1px var(--adm-color-text-light-solid);
  }
}

@class-prefix-progress-bar: ~'adm-progress-bar';

.@{class-prefix-progress-bar} {
  --track-width: var(--adm-progress-bar-track-width, 8px);
  --track-color: var(--adm-progress-bar-track-color, var(--adm-color-border));
  --fill-color: var(--adm-progress-bar-fill-color, var(--adm-color-primary));
  --text-width: var(--adm-progress-bar-text-width, 40px);

  display: flex;
  align-items: center;
  &-trail {
    flex: auto;
    background: var(--track-color);
    overflow: hidden;
    height: var(--track-width);
  }
  &-fill {
    transition: width 0.3s;
    background: var(--fill-color);
    height: var(--track-width);
  }
  &-text {
    flex: none;
    width: calc(var(--text-width) + 8px);
    padding-left: 8px;
    color: var(--adm-color-weak);
  }
}

.@{class-prefix-progress-bar}-rounded {
  .@{class-prefix-progress-bar}-trail,
  .@{class-prefix-progress-bar}-fill {
    border-radius: var(--track-width);
  }
}

@class-prefix-tab-bar: ~'adm-tab-bar';

.@{class-prefix-tab-bar} {
  &-wrap {
    display: flex;
    flex-wrap: nowrap;
    justify-content: flex-start;
    align-items: stretch;
    overflow: hidden;
    min-height: 48px;
  }

  &-item {
    flex: 1;
    color: var(--adm-color-text-secondary);
    white-space: nowrap;
    padding: 4px 8px;
    width: min-content;
    position: relative;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-direction: column;
  }

  &-item-icon {
    font-size: 24px;
    height: 24px;
    line-height: 1;
  }

  &-item-title {
    font-size: var(--adm-font-size-2);
    line-height: 15px;
    &-with-icon {
      margin-top: 2px;
    }
  }

  &-item-active {
    color: var(--adm-color-primary);
  }

  &-icon-badge {
    --top: 6px;
  }
  &-title-badge {
    --right: -2px;
    --top: -2px;
  }
}

@class-prefix-toast: ~'adm-toast';

.@{class-prefix-toast}-mask {
  .@{class-prefix-toast}-wrap {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    text-align: center;
  }
  .@{class-prefix-toast}-main {
    display: inline-block;
    position: relative;
    top: 50%;
    transform: translateY(-50%);
    width: auto;
    max-width: 204px;
    max-height: 70%;
    overflow: auto;
    color: white;
    word-break: break-all;
    background-color: rgba(0, 0, 0, 0.7);
    border-radius: 8px;
    pointer-events: all;
    font-size: var(--adm-font-size-7);
    line-height: 1.5;
    box-sizing: border-box;
    text-align: initial;
  }
  .@{class-prefix-toast}-main-text {
    padding: 12px;
    min-width: 0;
  }
  .@{class-prefix-toast}-main-icon {
    padding: 35px 12px;
    min-width: 150px;
    .@{class-prefix-toast}-icon {
      text-align: center;
      margin-bottom: 8px;
      font-size: 36px;
      line-height: 1;
    }
  }
}

.@{class-prefix-toast}-loading {
  --size: 48px;
  margin: 0 auto 8px;
}

// Image Mixins
// - Responsive image
// - Retina image


// Responsive image
//
// Keep images from scaling beyond the width of their parents.
.img-responsive(@display: block) {
  display: @display;
  max-width: 100%; // Part 1: Set a maximum relative to the parent
  height: auto; // Part 2: Scale the height according to the width, otherwise you get stretching
}


// Retina image
//
// Short retina mixin for setting background-image and -size. Note that the
// spelling of `min--moz-device-pixel-ratio` is intentional.
.img-retina(@file-1x; @file-2x; @width-1x; @height-1x) {
  background-image: url("@{file-1x}");

  @media
  only screen and (-webkit-min-device-pixel-ratio: 2),
  only screen and (min--moz-device-pixel-ratio: 2),
  only screen and (-o-min-device-pixel-ratio: 2 / 1),
  only screen and (min-device-pixel-ratio: 2),
  only screen and (min-resolution: 192dpi),
  only screen and (min-resolution: 2dppx) {
    background-image: url("@{file-2x}");
    background-size: @width-1x @height-1x;
  }
}

// Image Mixins
